1	const PROCESSING_FEE = 5;
2	const DEDUCTIBLE = 100;
3	const CAP_MULTIPLIER = 2;
4	
5	type ItemCatalogEntry = { basePremium: number; insuranceValue: number };
6	
7	const ITEM_CATALOG: Record<string, ItemCatalogEntry> = {
8	  sword:     { basePremium: 100, insuranceValue: 1000 },
9	  amulet:    { basePremium:  60, insuranceValue:  600 },
10	  staff:     { basePremium:  80, insuranceValue:  800 },
11	  potion:    { basePremium:  40, insuranceValue:  400 },
12	  rune:      { basePremium:  25, insuranceValue:  250 },
13	  moonstone: { basePremium:  25, insuranceValue:  250 },
14	};
15	
16	type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
17	type Customer = { yearsWithMHPCO: number };
18	type QuoteStep = { op: "quote"; items: Item[] };
19	type Damage = { itemType: string; amount: number };
20	type Incident = { cause: string; damages: Damage[] };
21	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
22	type Step = QuoteStep | ClaimStep;
23	type Scenario = { customer: Customer; steps: Step[] };
24	
25	const basePremiumFor = (item: Item): number => ITEM_CATALOG[item.type].basePremium;
26	
27	const COMPONENT_BLOCK_SIZE = 3;
28	const COMPONENT_BLOCK_PREMIUM = 60;
29	
30	const sumBy = <T>(xs: T[], f: (x: T) => number): number =>
31	  xs.reduce((sum, x) => sum + f(x), 0);
32	
33	const groupByType = (items: Item[]): Item[][] => {
34	  const groups = new Map<string, Item[]>();
35	  for (const item of items) {
36	    const group = groups.get(item.type) ?? [];
37	    group.push(item);
38	    groups.set(item.type, group);
39	  }
40	  return [...groups.values()];
41	};
42	
43	const basePremiumForGroup = (group: Item[]): number =>
44	  group.length === COMPONENT_BLOCK_SIZE
45	    ? COMPONENT_BLOCK_PREMIUM
46	    : sumBy(group, basePremiumFor);
47	
48	const totalBasePremium = (items: Item[]): number =>
49	  sumBy(groupByType(items), basePremiumForGroup);
50	
51	const CURSE_SURCHARGE_RATE = 0.5;
52	const HIGH_ENCHANTMENT_RATE = 0.3;
53	const HIGH_ENCHANTMENT_THRESHOLD = 5;
54	const FIRST_INSURANCE_RATE = 0.1;
55	const LOYALTY_DISCOUNT_RATE = -0.2;
56	const LOYALTY_YEARS_THRESHOLD = 2;
57	const FOLLOW_UP_DISCOUNT_RATE = -0.15;
58	
59	type PolicyContext = { customer: Customer; isFollowUp: boolean };
60	
61	const isCursed = (item: Item): boolean => item.cursed === true;
62	const isHighlyEnchanted = (item: Item): boolean =>
63	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
64	
65	type Modifier<T> = { applies: (subject: T) => boolean; rate: number };
66	
67	const sumApplicableRates = <T>(modifiers: Modifier<T>[], subject: T): number =>
68	  sumBy(modifiers, ({ applies, rate }) => (applies(subject) ? rate : 0));
69	
70	const ITEM_SURCHARGES: Modifier<Item>[] = [
71	  { applies: isCursed, rate: CURSE_SURCHARGE_RATE },
72	  { applies: isHighlyEnchanted, rate: HIGH_ENCHANTMENT_RATE },
73	];
74	
75	const isLoyalCustomer = (ctx: PolicyContext): boolean =>
76	  ctx.customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD;
77	const isFollowUpContract = (ctx: PolicyContext): boolean => ctx.isFollowUp;
78	
79	// First-insurance rate applies to every quote unconditionally;
80	// other policy modifiers are conditional on the customer/contract context.
81	const POLICY_MODIFIERS: Modifier<PolicyContext>[] = [
82	  { applies: isLoyalCustomer, rate: LOYALTY_DISCOUNT_RATE },
83	  { applies: isFollowUpContract, rate: FOLLOW_UP_DISCOUNT_RATE },
84	];
85	
86	const policyAdjustment = (baseTotal: number, ctx: PolicyContext): number =>
87	  baseTotal * (FIRST_INSURANCE_RATE + sumApplicableRates(POLICY_MODIFIERS, ctx));
88	
89	const itemSurchargeFor = (item: Item): number =>
90	  basePremiumFor(item) * sumApplicableRates(ITEM_SURCHARGES, item);
91	
92	const itemSurchargesTotal = (items: Item[]): number =>
93	  sumBy(items, itemSurchargeFor);
94	
95	const premiumFor = (items: Item[], ctx: PolicyContext): number => {
96	  const baseTotal = totalBasePremium(items);
97	  return Math.ceil(
98	    baseTotal +
99	      itemSurchargesTotal(items) +
100	      policyAdjustment(baseTotal, ctx) +
101	      PROCESSING_FEE,
102	  );
103	};
104	
105	const insuranceValueFor = (item: Item): number => ITEM_CATALOG[item.type].insuranceValue;
106	
107	const insuranceSumFor = (items: Item[]): number => sumBy(items, insuranceValueFor);
108	
109	const HIGH_DAMAGE_ENCHANTMENT_THRESHOLD = 8;
110	const HIGH_DAMAGE_ENCHANTMENT_RATE = 0.5;
111	
112	const reimbursableAmount = (damage: Damage, item: Item): number =>
113	  (item.enchantment ?? 0) >= HIGH_DAMAGE_ENCHANTMENT_THRESHOLD
114	    ? damage.amount * HIGH_DAMAGE_ENCHANTMENT_RATE
115	    : damage.amount;
116	
117	const payoutForDamage = (damage: Damage, item: Item): number =>
118	  reimbursableAmount(damage, item) - DEDUCTIBLE;
119	
120	const claimResultFor = (
121	  step: ClaimStep,
122	  steps: Step[],
123	): { payout: number; remainingCap: number } => {
124	  const policy = steps[step.policy] as QuoteStep;
125	  const cap = insuranceSumFor(policy.items) * CAP_MULTIPLIER;
126	  const payout = sumBy(step.incident.damages, (damage) => {
127	    const item = policy.items.find((i) => i.type === damage.itemType)!;
128	    return payoutForDamage(damage, item);
129	  });
130	  return { payout, remainingCap: cap - payout };
131	};
132	
133	const quoteResultFor = (step: QuoteStep, ctx: PolicyContext) => ({
134	  premium: premiumFor(step.items, ctx),
135	});
136	
137	const policyContextFor = (scenario: Scenario, stepIndex: number): PolicyContext => ({
138	  customer: scenario.customer,
139	  isFollowUp: stepIndex > 0,
140	});
141	
142	export const runScenario = (input: unknown): unknown => {
143	  const scenario = input as Scenario;
144	  return {
145	    results: scenario.steps.map((step, index) =>
146	      step.op === "quote"
147	        ? quoteResultFor(step, policyContextFor(scenario, index))
148	        : claimResultFor(step, scenario.steps),
149	    ),
150	  };
151	};
